// Gemini レスポンスから診断JSONを抽出
const resp = $input.first().json;
let text = '';
try {
  text = resp.candidates[0].content.parts[0].text || '';
} catch(e) { text = ''; }

text = text.replace(/```json\s*/g, '').replace(/```/g, '').trim();
let diagnosis = {};
try { diagnosis = JSON.parse(text); } catch(e) { diagnosis = { error: 'パースエラー', raw: text }; }

const formData = $('フォームデータ正規化').item.json;

return [{
  json: {
    ...formData,
    diagnosis,
    email_body: diagnosis.email_body || '',
    overall_score: diagnosis.overall_score || 0,
  }
}];

